package ru.memearena.meme.api; import ru.memearena.meme.domain.*; import java.time.Instant; import java.util.UUID; public record MemeResponse(UUID id,String title,String imageUrl,String sourceUrl,ModerationStatus moderationStatus,int rating,long wins,long losses,long battlesCount,Instant createdAt){ public static MemeResponse from(Meme m){return new MemeResponse(m.getId(),m.getTitle(),m.getImageUrl(),m.getSourceUrl(),m.getModerationStatus(),m.getRating(),m.getWins(),m.getLosses(),m.getBattlesCount(),m.getCreatedAt());}}
